<?php include 'header.php'; if(empty($_SESSION['cart'])){ header('Location: cart.php'); exit; }
$msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $ids=array_keys($_SESSION['cart']); $in=implode(',',array_fill(0,count($ids),'?')); $st=$pdo->prepare("SELECT * FROM products WHERE id IN ($in)"); $st->execute($ids); $products=$st->fetchAll(); $total=0; foreach($products as $p){$total+=productPrice($p)*$_SESSION['cart'][$p['id']];}
$pdo->beginTransaction(); $st=$pdo->prepare('INSERT INTO orders(customer_name,phone,address,note,total) VALUES(?,?,?,?,?)'); $st->execute([$_POST['name'],$_POST['phone'],$_POST['address'],$_POST['note'],$total]); $oid=$pdo->lastInsertId(); $it=$pdo->prepare('INSERT INTO order_items(order_id,product_id,quantity,price,size) VALUES(?,?,?,?,?)'); foreach($products as $p){$it->execute([$oid,$p['id'],$_SESSION['cart'][$p['id']],productPrice($p),$_SESSION['sizes'][$p['id']]??'']);} $pdo->commit(); unset($_SESSION['cart'],$_SESSION['sizes']); $msg='Đặt hàng thành công. Mã đơn hàng: #'.$oid; }
?>
<section class="section"><div class="section-title"><h2>Thanh toán</h2></div><?php if($msg): ?><div class="notice"><?=$msg?></div><a class="btn" href="index.php">Về trang chủ</a><?php else: ?><form class="form" method="post"><input name="name" required placeholder="Họ tên"><input name="phone" required placeholder="Số điện thoại"><input name="address" required placeholder="Địa chỉ nhận hàng"><textarea name="note" placeholder="Ghi chú"></textarea><button class="btn">Hoàn tất đặt hàng</button></form><?php endif; ?></section><?php include 'footer.php'; ?>
